const data = $input.first().json;
const feriado = data.feriado;
const date = data.date;

const d = new Date(date + 'T09:00:00');
const meses = ['janeiro','fevereiro','março','abril','maio','junho','julho','agosto','setembro','outubro','novembro','dezembro'];
const dataFormatada = `${d.getDate()} de ${meses[d.getMonth()]} de ${d.getFullYear()} às 09:00`;

const contexto = feriado
  ? `Hoje é feriado nacional: ${feriado}.`
  : d.getDay() === 0 ? 'Hoje é domingo.' : 'Hoje é sábado.';

return [{ json: { dataFormatada, contexto, date } }];

